Thread pool(C++11)The easy thread pool main function are as follows:
#include &lt;vector>
#include &lt;queue>
using namespace std;

class ThreadPool&#123;
public:
	void startup();
	void QueueJob(const std::function&lt;void()&amp; job);
	void stop();
	void busy();

private:
	void ThreadLoop();
	bool terminate = false;
	mutex queue_mutex;
	vector&lt;thread> threads;
	queue&lt;function&lt;void()>> jobs;

&#125;

1. startupEach thread should be running its own infinite loop, constantly waiting for new tasks to grab and run.
void ThreadPool::start()
&#123;
    // Max # of threads the system supports
    const uint32_t num_threads = std::thread::hardware_concurrency();
    threads.resize(num_threads);
    for(uint32_t i = 0; i &lt; num_threads; i++)
        threads.at(i) = std::thread(ThreadLoop);
&#125;


2. ThreadLoopThe infinite loop function. This is a while(true) loop waiting for the task queue to open up.
void ThreadPool::ThreadLoop() &#123;
    while (true) &#123;
        std::function&lt;void()> job;
        &#123;
            std::unique_lock&lt;std::mutex> lock(queue_mutex);
            mutex_condition.wait(lock, [this] &#123;
                return !jobs.empty() || should_terminate;
            &#125;);
            if (should_terminate) &#123;
                return;
            &#125;
            job = jobs.front();
            jobs.pop();
        &#125;
        job();
    &#125;
&#125;

3. QueueJobAdd a new job to the pool; use a lock so that there isn’t a data race.
void ThreadPool::QueueJob(const std::function&lt;void()>&amp; job) &#123;
    &#123;
        std::unique_lock&lt;std::mutex> lock(queue_mutex);
        jobs.push(job);
    &#125;
    mutex_condition.notify_one();
&#125;

4. busyThe busy()function can be used in a while loop, such that the main thread can wait the threadpool to complete all the tasks before calling the threadpool destructor.
void ThreadPool::busy() &#123;
    bool poolbusy;
    &#123;
        std::unique_lock&lt;std::mutex> lock(queue_mutex);
        poolbusy = jobs.empty();
    &#125;
    return poolbusy;
&#125;

5. stopvoid ThreadPool::Stop() &#123;
    &#123;
        std::unique_lock&lt;std::mutex> lock(queue_mutex);
        should_terminate = true;
    &#125;
    mutex_condition.notify_all();
    for (std::thread&amp; active_thread : threads) &#123;
        active_thread.join();
    &#125;
    threads.clear();
&#125;

