Readn read the data
ssize_t readn(int fd, void* buf, size_t len)
&#123;
    char *pos = (char*)buf;
    size_t leftNum = len;
    ssize_t readNum = 0;
    while(leftNum > 0)
    &#123;
        ssize_t tmpRead = read(fd, pos, leftNum);
        if(tmpRead &lt; 0)
        &#123;
            if(errno == EINTR)
                tmpRead = 0;
            else if (errno == EAGAIN)
                return readNum;
            else
                return -1;
        &#125;
        // tmpread == 0 ,the connection is close
        if(tmpRead == 0)
            break;
        readNum += tmpRead;
        pos += tmpRead;

        leftNum -= tmpRead;
    &#125;
    return readNum;
&#125;

writen
ssize_t writen(int fd, const void* buf, size_t len, bool isWrite)
&#123;
    char *pos = (char*)buf;
    size_t leftNum = len;
    ssize_t writtenNum = 0;
    while(leftNum > 0)
    &#123;
        ssize_t tmpWrite = 0;

        if(isWrite)
            tmpWrite = write(fd, pos, leftNum);
        else
            tmpWrite = send(fd, pos, leftNum, 0);

        if(tmpWrite &lt; 0)
        &#123;
            if(errno == EINTR || errno == EAGAIN)
                tmpWrite = 0;
            else
                return -1;
        &#125;
        if(tmpWrite == 0)
            break;
        writtenNum += tmpWrite;
        pos += tmpWrite;
        leftNum -= tmpWrite;
    &#125;
    return writtenNum;
&#125;

